let collection = []//{link,kind}

$("LINKS").first().json.links.forEach(link=>{
  const value = link.href || link.src
  const kind = (link)=>{
    if(value.includes("vimeo.com")) {return "vimeo"}
    if(value.startsWith('/')) {return "platform"}
    if(value.startsWith('https://user.oc-static.com/')){return "static"}

    return "other"
  }
  collection.push({link:value,kind:kind(link)})
})

return collection
